import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as c,o as t,c as i,a,b as s,d as e,e as l}from"./app-4392f80b.js";const r={},p=l(`<h1 id="java-并发之-aqs" tabindex="-1"><a class="header-anchor" href="#java-并发之-aqs" aria-hidden="true">#</a> Java 并发之 AQS</h1><blockquote><p><code>AbstractQueuedSynchronizer</code>（简称 <strong>AQS</strong>）是<strong>队列同步器</strong>，顾名思义，其主要作用是处理同步。它是并发锁和很多同步工具类的实现基石（如 <code>ReentrantLock</code>、<code>ReentrantReadWriteLock</code>、<code>CountDownLatch</code>、<code>Semaphore</code>、<code>FutureTask</code> 等）。</p></blockquote><h2 id="aqs-的要点" tabindex="-1"><a class="header-anchor" href="#aqs-的要点" aria-hidden="true">#</a> AQS 的要点</h2><p><strong>AQS 提供了对独享锁与共享锁的支持</strong>。</p><p>在 <code>java.util.concurrent.locks</code> 包中的相关锁（常用的有 <code>ReentrantLock</code>、 <code>ReadWriteLock</code>）都是基于 AQS 来实现。这些锁都没有直接继承 AQS，而是定义了一个 <code>Sync</code> 类去继承 AQS。为什么要这样呢？因为锁面向的是使用用户，而同步器面向的则是线程控制，那么在锁的实现中聚合同步器而不是直接继承 AQS 就可以很好的隔离二者所关注的事情。</p><h2 id="aqs-的应用" tabindex="-1"><a class="header-anchor" href="#aqs-的应用" aria-hidden="true">#</a> AQS 的应用</h2><p><strong>AQS 提供了对独享锁与共享锁的支持</strong>。</p><h3 id="独享锁-api" tabindex="-1"><a class="header-anchor" href="#独享锁-api" aria-hidden="true">#</a> 独享锁 API</h3><p>获取、释放独享锁的主要 API 如下：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">void</span> <span class="token function">acquire</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">void</span> <span class="token function">acquireInterruptibly</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">boolean</span> <span class="token function">tryAcquireNanos</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">,</span> <span class="token keyword">long</span> nanosTimeout<span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">boolean</span> <span class="token function">release</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>acquire</code> - 获取独占锁。</li><li><code>acquireInterruptibly</code> - 获取可中断的独占锁。</li><li><code>tryAcquireNanos</code> - 尝试在指定时间内获取可中断的独占锁。在以下三种情况下回返回： <ul><li>在超时时间内，当前线程成功获取了锁；</li><li>当前线程在超时时间内被中断；</li><li>超时时间结束，仍未获得锁返回 false。</li></ul></li><li><code>release</code> - 释放独占锁。</li></ul><h3 id="共享锁-api" tabindex="-1"><a class="header-anchor" href="#共享锁-api" aria-hidden="true">#</a> 共享锁 API</h3><p>获取、释放共享锁的主要 API 如下：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">void</span> <span class="token function">acquireShared</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">void</span> <span class="token function">acquireSharedInterruptibly</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">boolean</span> <span class="token function">tryAcquireSharedNanos</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">,</span> <span class="token keyword">long</span> nanosTimeout<span class="token punctuation">)</span>
<span class="token keyword">public</span> <span class="token keyword">final</span> <span class="token keyword">boolean</span> <span class="token function">releaseShared</span><span class="token punctuation">(</span><span class="token keyword">int</span> arg<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>acquireShared</code> - 获取共享锁。</li><li><code>acquireSharedInterruptibly</code> - 获取可中断的共享锁。</li><li><code>tryAcquireSharedNanos</code> - 尝试在指定时间内获取可中断的共享锁。</li><li><code>release</code> - 释放共享锁。</li></ul><h2 id="aqs-的原理" tabindex="-1"><a class="header-anchor" href="#aqs-的原理" aria-hidden="true">#</a> AQS 的原理</h2><blockquote><p>ASQ 原理要点：</p><ul><li>AQS 使用一个整型的 <code>volatile</code> 变量来 <strong>维护同步状态</strong>。状态的意义由子类赋予。</li><li>AQS 维护了一个 FIFO 的双链表，用来存储获取锁失败的线程。</li></ul><p>AQS 围绕同步状态提供两种基本操作“获取”和“释放”，并提供一系列判断和处理方法，简单说几点：</p><ul><li>state 是独占的，还是共享的；</li><li>state 被获取后，其他线程需要等待；</li><li>state 被释放后，唤醒等待线程；</li><li>线程等不及时，如何退出等待。</li></ul><p>至于线程是否可以获得 state，如何释放 state，就不是 AQS 关心的了，要由子类具体实现。</p></blockquote><h3 id="aqs-的数据结构" tabindex="-1"><a class="header-anchor" href="#aqs-的数据结构" aria-hidden="true">#</a> AQS 的数据结构</h3><p>阅读 AQS 的源码，可以发现：AQS 继承自 <code>AbstractOwnableSynchronize</code>。</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">abstract</span> <span class="token keyword">class</span> <span class="token class-name">AbstractQueuedSynchronizer</span>
    <span class="token keyword">extends</span> <span class="token class-name">AbstractOwnableSynchronizer</span>
    <span class="token keyword">implements</span> <span class="token class-name"><span class="token namespace">java<span class="token punctuation">.</span>io<span class="token punctuation">.</span></span>Serializable</span> <span class="token punctuation">{</span>

    <span class="token doc-comment comment">/** 等待队列的队头，懒加载。只能通过 setHead 方法修改。 */</span>
    <span class="token keyword">private</span> <span class="token keyword">transient</span> <span class="token keyword">volatile</span> <span class="token class-name">Node</span> head<span class="token punctuation">;</span>
    <span class="token doc-comment comment">/** 等待队列的队尾，懒加载。只能通过 enq 方法添加新的等待节点。*/</span>
    <span class="token keyword">private</span> <span class="token keyword">transient</span> <span class="token keyword">volatile</span> <span class="token class-name">Node</span> tail<span class="token punctuation">;</span>
    <span class="token doc-comment comment">/** 同步状态 */</span>
    <span class="token keyword">private</span> <span class="token keyword">volatile</span> <span class="token keyword">int</span> state<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>state</code> - AQS 使用一个整型的 <code>volatile</code> 变量来 <strong>维护同步状态</strong>。 <ul><li>这个整数状态的意义由子类来赋予，如<code>ReentrantLock</code> 中该状态值表示所有者线程已经重复获取该锁的次数，<code>Semaphore</code> 中该状态值表示剩余的许可数量。</li></ul></li><li><code>head</code> 和 <code>tail</code> - AQS <strong>维护了一个 <code>Node</code> 类型（AQS 的内部类）的双链表来完成同步状态的管理</strong>。这个双链表是一个双向的 FIFO 队列，通过 <code>head</code> 和 <code>tail</code> 指针进行访问。当 <strong>有线程获取锁失败后，就被添加到队列末尾</strong>。</li></ul><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/cs/java/javacore/concurrent/aqs_1.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>再来看一下 <code>Node</code> 的源码</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">class</span> <span class="token class-name">Node</span> <span class="token punctuation">{</span>
    <span class="token doc-comment comment">/** 该等待同步的节点处于共享模式 */</span>
    <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">Node</span> <span class="token constant">SHARED</span> <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Node</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token doc-comment comment">/** 该等待同步的节点处于独占模式 */</span>
    <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token class-name">Node</span> <span class="token constant">EXCLUSIVE</span> <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/** 线程等待状态，状态值有: 0、1、-1、-2、-3 */</span>
    <span class="token keyword">volatile</span> <span class="token keyword">int</span> waitStatus<span class="token punctuation">;</span>
    <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">int</span> <span class="token constant">CANCELLED</span> <span class="token operator">=</span>  <span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">int</span> <span class="token constant">SIGNAL</span>    <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">int</span> <span class="token constant">CONDITION</span> <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">2</span><span class="token punctuation">;</span>
    <span class="token keyword">static</span> <span class="token keyword">final</span> <span class="token keyword">int</span> <span class="token constant">PROPAGATE</span> <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">3</span><span class="token punctuation">;</span>

    <span class="token doc-comment comment">/** 前驱节点 */</span>
    <span class="token keyword">volatile</span> <span class="token class-name">Node</span> prev<span class="token punctuation">;</span>
    <span class="token doc-comment comment">/** 后继节点 */</span>
    <span class="token keyword">volatile</span> <span class="token class-name">Node</span> next<span class="token punctuation">;</span>
    <span class="token doc-comment comment">/** 等待锁的线程 */</span>
    <span class="token keyword">volatile</span> <span class="token class-name">Thread</span> thread<span class="token punctuation">;</span>

  	<span class="token doc-comment comment">/** 和节点是否共享有关 */</span>
    <span class="token class-name">Node</span> nextWaiter<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>很显然，Node 是一个双链表结构。</p><ul><li><code>waitStatus</code> - <code>Node</code> 使用一个整型的 <code>volatile</code> 变量来 维护 AQS 同步队列中线程节点的状态。<code>waitStatus</code> 有五个状态值： <ul><li><code>CANCELLED(1)</code> - 此状态表示：该节点的线程可能由于超时或被中断而 <strong>处于被取消(作废)状态</strong>，一旦处于这个状态，表示这个节点应该从等待队列中移除。</li><li><code>SIGNAL(-1)</code> - 此状态表示：<strong>后继节点会被挂起</strong>，因此在当前节点释放锁或被取消之后，必须唤醒(<code>unparking</code>)其后继结点。</li><li><code>CONDITION(-2)</code> - 此状态表示：该节点的线程 <strong>处于等待条件状态</strong>，不会被当作是同步队列上的节点，直到被唤醒(<code>signal</code>)，设置其值为 0，再重新进入阻塞状态。</li><li><code>PROPAGATE(-3)</code> - 此状态表示：下一个 <code>acquireShared</code> 应无条件传播。</li><li>0 - 非以上状态。</li></ul></li></ul><h3 id="独占锁的获取和释放" tabindex="-1"><a class="header-anchor" href="#独占锁的获取和释放" aria-hidden="true">#</a> 独占锁的获取和释放</h3><h4 id="获取独占锁" tabindex="-1"><a class="header-anchor" href="#获取独占锁" aria-hidden="true">#</a> 获取独占锁</h4><p>AQS 中使用 <code>acquire(int arg)</code> 方法获取独占锁，其大致流程如下：</p><ol><li>先尝试获取同步状态，如果获取同步状态成功，则结束方法，直接返回。</li><li>如果获取同步状态不成功，AQS 会不断尝试利用 CAS 操作将当前线程插入等待同步队列的队尾，直到成功为止。</li><li>接着，不断尝试为等待队列中的线程节点获取独占锁。</li></ol><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/cs/java/javacore/concurrent/aqs_2.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/cs/java/javacore/concurrent/aqs_3.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>详细流程可以用下图来表示，请结合源码来理解（一图胜千言）：</p><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/cs/java/javacore/concurrent/aqs_4.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h4 id="释放独占锁" tabindex="-1"><a class="header-anchor" href="#释放独占锁" aria-hidden="true">#</a> 释放独占锁</h4><p>AQS 中使用 <code>release(int arg)</code> 方法释放独占锁，其大致流程如下：</p><ol><li>先尝试获取解锁线程的同步状态，如果获取同步状态不成功，则结束方法，直接返回。</li><li>如果获取同步状态成功，AQS 会尝试唤醒当前线程节点的后继节点。</li></ol><h4 id="获取可中断的独占锁" tabindex="-1"><a class="header-anchor" href="#获取可中断的独占锁" aria-hidden="true">#</a> 获取可中断的独占锁</h4><p>AQS 中使用 <code>acquireInterruptibly(int arg)</code> 方法获取可中断的独占锁。</p><p><code>acquireInterruptibly(int arg)</code> 实现方式<strong>相较于获取独占锁方法（ <code>acquire</code>）非常相似</strong>，区别仅在于它会<strong>通过 <code>Thread.interrupted</code> 检测当前线程是否被中断</strong>，如果是，则立即抛出中断异常（<code>InterruptedException</code>）。</p><h4 id="获取超时等待式的独占锁" tabindex="-1"><a class="header-anchor" href="#获取超时等待式的独占锁" aria-hidden="true">#</a> 获取超时等待式的独占锁</h4><p>AQS 中使用 <code>tryAcquireNanos(int arg)</code> 方法获取超时等待的独占锁。</p><p>doAcquireNanos 的实现方式 <strong>相较于获取独占锁方法（ <code>acquire</code>）非常相似</strong>，区别在于它会根据超时时间和当前时间计算出截止时间。在获取锁的流程中，会不断判断是否超时，如果超时，直接返回 false；如果没超时，则用 <code>LockSupport.parkNanos</code> 来阻塞当前线程。</p><h3 id="共享锁的获取和释放" tabindex="-1"><a class="header-anchor" href="#共享锁的获取和释放" aria-hidden="true">#</a> 共享锁的获取和释放</h3><h4 id="获取共享锁" tabindex="-1"><a class="header-anchor" href="#获取共享锁" aria-hidden="true">#</a> 获取共享锁</h4><p>AQS 中使用 <code>acquireShared(int arg)</code> 方法获取共享锁。</p><p><code>acquireShared</code> 方法和 <code>acquire</code> 方法的逻辑很相似，区别仅在于自旋的条件以及节点出队的操作有所不同。</p><p>成功获得共享锁的条件如下：</p><ul><li><code>tryAcquireShared(arg)</code> 返回值大于等于 0 （这意味着共享锁的 permit 还没有用完）。</li><li>当前节点的前驱节点是头结点。</li></ul><h4 id="释放共享锁" tabindex="-1"><a class="header-anchor" href="#释放共享锁" aria-hidden="true">#</a> 释放共享锁</h4><p>AQS 中使用 <code>releaseShared(int arg)</code> 方法释放共享锁。</p><p><code>releaseShared</code> 首先会尝试释放同步状态，如果成功，则解锁一个或多个后继线程节点。释放共享锁和释放独享锁流程大体相似，区别在于：</p><p>对于独享模式，如果需要 SIGNAL，释放仅相当于调用头节点的 <code>unparkSuccessor</code>。</p><h4 id="获取可中断的共享锁" tabindex="-1"><a class="header-anchor" href="#获取可中断的共享锁" aria-hidden="true">#</a> 获取可中断的共享锁</h4><p>AQS 中使用 <code>acquireSharedInterruptibly(int arg)</code> 方法获取可中断的共享锁。</p><p><code>acquireSharedInterruptibly</code> 方法与 <code>acquireInterruptibly</code> 几乎一致，不再赘述。</p><h4 id="获取超时等待式的共享锁" tabindex="-1"><a class="header-anchor" href="#获取超时等待式的共享锁" aria-hidden="true">#</a> 获取超时等待式的共享锁</h4><p>AQS 中使用 <code>tryAcquireSharedNanos(int arg)</code> 方法获取超时等待式的共享锁。</p><p><code>tryAcquireSharedNanos</code> 方法与 <code>tryAcquireNanos</code> 几乎一致，不再赘述。</p><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>`,60),d={href:"https://book.douban.com/subject/10484692/",target:"_blank",rel:"noopener noreferrer"},u={href:"https://book.douban.com/subject/26591326/",target:"_blank",rel:"noopener noreferrer"},k={href:"https://www.cnblogs.com/dolphin0520/p/3923167.html",target:"_blank",rel:"noopener noreferrer"},h={href:"https://zhuanlan.zhihu.com/p/27134110",target:"_blank",rel:"noopener noreferrer"},m={href:"https://t.hao0.me/java/2016/04/01/aqs.html",target:"_blank",rel:"noopener noreferrer"},v={href:"https://www.cnblogs.com/qifengshi/p/6831055.html",target:"_blank",rel:"noopener noreferrer"};function b(g,y){const n=c("ExternalLinkIcon");return t(),i("div",null,[p,a("ul",null,[a("li",null,[a("a",d,[s("《Java 并发编程实战》"),e(n)])]),a("li",null,[a("a",u,[s("《Java 并发编程的艺术》"),e(n)])]),a("li",null,[a("a",k,[s("Java 并发编程：Lock"),e(n)])]),a("li",null,[a("a",h,[s("深入学习 java 同步器 AQS"),e(n)])]),a("li",null,[a("a",m,[s("AbstractQueuedSynchronizer 框架"),e(n)])]),a("li",null,[a("a",v,[s("Java 中的锁分类"),e(n)])])])])}const S=o(r,[["render",b],["__file","Java并发之AQS.html.vue"]]);export{S as default};
